import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { discoverBackends } from './backend-discovery.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const backends = discoverBackends();

const registryContent = `/**
 * Generated by scripts/generate-registry.js
 * DO NOT EDIT MANUALLY
 */

export const BACKENDS = ${JSON.stringify(
  backends.map((b) => ({
    config: b.configKey,
    path: b.path,
  })),
  null,
  2
)};

export async function getBackendClass(path) {
${backends
  .map(
    (b) =>
      `  if (path === '${b.path}') { return (await import('${b.path}')).default; }`
  )
  .join('\n')}
  throw new Error(\`Unknown backend path "\${path}"\`);
}
`;

fs.writeFileSync(
  path.resolve(__dirname, '../backends-registry.js'),
  registryContent
);
console.log('Successfully generated backends-registry.js');
